import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export enum Specialty {
  GENERAL = 'Đa khoa',
  ENT = 'Tai Mũi Họng',
  DERMATOLOGY = 'Da liễu',
  PEDIATRICS = 'Nhi khoa',
  CARDIOLOGY = 'Tim mạch',
  NEUROLOGY = 'Thần kinh',
  GASTROENTEROLOGY = 'Tiêu hóa',
  RESPIRATORY = 'Hô hấp'
}

export interface Doctor {
  id: string;
  name: string;
  specialty: Specialty;
  experience: number;
  rating: number;
  nextAvailable: string;
  price: number;
  image: string;
}

export interface ChatState {
  messages: Message[];
  isLoading: boolean;
  error: string | null;
}

import { GoogleGenAI, ChatSession, GenerativeModel } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let chatSession: ChatSession | null = null;
let model: GenerativeModel | null = null;

export const initializeChat = async () => {
  try {
    // We use the conversational chat interface
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7, // Balanced for friendly but accurate responses
        topK: 40,
        topP: 0.95,
      },
    });
    return true;
  } catch (error) {
    console.error("Failed to initialize chat:", error);
    return false;
  }
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    await initializeChat();
  }

  if (!chatSession) {
    throw new Error("Chat session could not be initialized.");
  }

  try {
    const response = await chatSession.sendMessage({ message });
    return response.text || "Xin lỗi, tôi gặp sự cố khi xử lý phản hồi. Vui lòng thử lại.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Không thể kết nối với hệ thống AI.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Loader2, AlertTriangle, Info } from 'lucide-react';
import { Message } from '../types';
import { sendMessageToGemini } from '../services/geminiService';

interface ChatInterfaceProps {
  onSpecialtyDetected?: (text: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onSpecialtyDetected }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'init-1',
      role: 'model',
      text: "Xin chào, tôi là trợ lý y tế AI. Tôi có thể giúp gì cho sức khỏe của bạn hôm nay? \n\n*Lưu ý: Tôi là AI sàng lọc ban đầu, không thay thế bác sĩ.*",
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(userMessage.text);

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };

      setMessages(prev => [...prev, botMessage]);

      // Simple heuristic to detect if the AI suggests booking or mentions a specialty
      // This allows the parent component to highlight the doctor list if needed
      // In a real app, we'd use function calling for precise triggers.
      if (onSpecialtyDetected) {
          onSpecialtyDetected(responseText);
      }

    } catch (error) {
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Xin lỗi, đã có lỗi xảy ra khi kết nối. Vui lòng thử lại sau.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Helper to render markdown-like text safely
  const renderText = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Bold handling
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <div key={i} className={`min-h-[1.2em] ${line.trim().startsWith('-') ? 'ml-4' : ''}`}>
           {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={j} className="font-semibold text-slate-800">{part.slice(2, -2)}</strong>;
              }
              return <span key={j}>{part}</span>;
           })}
        </div>
      );
    });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Chat Header */}
      <div className="bg-teal-600 p-4 text-white flex items-center justify-between shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <Bot size={24} className="text-white" />
          </div>
          <div>
            <h2 className="font-bold text-lg leading-tight">Trợ Lý Sức Khỏe AI</h2>
            <p className="text-teal-100 text-xs flex items-center gap-1">
              <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
              Sẵn sàng hỗ trợ
            </p>
          </div>
        </div>
        <div className="hidden sm:block text-right">
           <p className="text-xs text-teal-100 italic opacity-80 max-w-[200px]">"Không thay thế bác sĩ"</p>
        </div>
      </div>

      {/* Safety Banner */}
      <div className="bg-amber-50 border-b border-amber-100 px-4 py-2 flex items-start gap-2 text-xs text-amber-800">
        <AlertTriangle size={14} className="mt-0.5 shrink-0 text-amber-600" />
        <p>
          AI chỉ sàng lọc ban đầu. <strong>Gọi 115 ngay</strong> nếu khó thở, đau ngực dữ dội, hoặc lơ mơ.
        </p>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-slate-50">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div
              className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 
                ${msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-teal-600 text-white'}`}
            >
              {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>

            <div
              className={`max-w-[85%] sm:max-w-[75%] rounded-2xl px-4 py-3 shadow-sm text-sm leading-relaxed
                ${msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'}`}
            >
              {renderText(msg.text)}
              <div 
                className={`text-[10px] mt-2 text-right opacity-70 
                ${msg.role === 'user' ? 'text-blue-100' : 'text-slate-400'}`}
              >
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-3">
            <div className="w-8 h-8 rounded-full bg-teal-600 flex items-center justify-center shrink-0">
               <Bot size={16} className="text-white" />
            </div>
            <div className="bg-white border border-slate-100 rounded-2xl rounded-tl-none px-4 py-3 shadow-sm flex items-center gap-2">
              <Loader2 size={16} className="animate-spin text-teal-600" />
              <span className="text-slate-400 text-sm">Đang phân tích triệu chứng...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-200">
        <div className="flex gap-2 relative">
          <input
            ref={inputRef}
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Mô tả triệu chứng của bạn (Ví dụ: Đau đầu, sốt nhẹ...)"
            disabled={isLoading}
            className="w-full bg-slate-50 border border-slate-300 text-slate-900 rounded-xl pl-4 pr-12 py-3 focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent placeholder-slate-400 transition-all disabled:opacity-60 disabled:cursor-not-allowed"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputText.trim() || isLoading}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors"
          >
            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
          </button>
        </div>
        <p className="text-center text-xs text-slate-400 mt-2">
          Thông tin được bảo mật và chỉ dùng để tư vấn đặt lịch.
        </p>
      </div>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { MOCK_DOCTORS, SPECIALTY_OPTIONS } from '../constants';
import { Doctor, Specialty } from '../types';
import { Star, Clock, MapPin, Calendar, Filter, Stethoscope } from 'lucide-react';

interface DoctorListProps {
  initialFilter?: string;
}

export const DoctorList: React.FC<DoctorListProps> = ({ initialFilter }) => {
  const [selectedSpecialty, setSelectedSpecialty] = useState<string>(initialFilter || 'All');

  const filteredDoctors = useMemo(() => {
    if (selectedSpecialty === 'All') return MOCK_DOCTORS;
    return MOCK_DOCTORS.filter(doc => doc.specialty === selectedSpecialty);
  }, [selectedSpecialty]);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 h-full flex flex-col overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 bg-slate-50">
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-bold text-lg text-slate-800 flex items-center gap-2">
            <Stethoscope size={20} className="text-teal-600" />
            Đặt Lịch Bác Sĩ
          </h2>
          <span className="text-xs font-medium bg-teal-100 text-teal-700 px-2 py-1 rounded-full">
            {filteredDoctors.length} bác sĩ
          </span>
        </div>

        {/* Filter Scroll */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button
            onClick={() => setSelectedSpecialty('All')}
            className={`whitespace-nowrap px-3 py-1.5 rounded-full text-xs font-medium transition-colors
              ${selectedSpecialty === 'All' 
                ? 'bg-teal-600 text-white' 
                : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
          >
            Tất cả
          </button>
          {SPECIALTY_OPTIONS.map((spec) => (
            <button
              key={spec}
              onClick={() => setSelectedSpecialty(spec)}
              className={`whitespace-nowrap px-3 py-1.5 rounded-full text-xs font-medium transition-colors
                ${selectedSpecialty === spec 
                  ? 'bg-teal-600 text-white' 
                  : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
            >
              {spec}
            </button>
          ))}
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/50">
        {filteredDoctors.length === 0 ? (
          <div className="text-center py-10 text-slate-400">
            <p>Không tìm thấy bác sĩ phù hợp.</p>
          </div>
        ) : (
          filteredDoctors.map((doctor) => (
            <div key={doctor.id} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow group">
              <div className="flex gap-4">
                <img 
                  src={doctor.image} 
                  alt={doctor.name} 
                  className="w-16 h-16 rounded-full object-cover border-2 border-slate-100"
                />
                <div className="flex-1">
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="font-bold text-slate-800 text-sm sm:text-base group-hover:text-teal-600 transition-colors">
                        {doctor.name}
                      </h3>
                      <p className="text-teal-600 text-xs font-medium">{doctor.specialty}</p>
                    </div>
                    <div className="flex items-center gap-1 text-amber-500 bg-amber-50 px-1.5 py-0.5 rounded text-xs">
                      <Star size={12} fill="currentColor" />
                      <span className="font-bold">{doctor.rating}</span>
                    </div>
                  </div>

                  <div className="mt-3 space-y-1.5">
                    <div className="flex items-center gap-2 text-xs text-slate-500">
                      <Clock size={14} className="text-slate-400" />
                      <span>Trống lịch: <span className="text-green-600 font-medium">{doctor.nextAvailable}</span></span>
                    </div>
                    <div className="flex items-center gap-2 text-xs text-slate-500">
                      <MapPin size={14} className="text-slate-400" />
                      <span>{doctor.experience} năm kinh nghiệm</span>
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-4 flex items-center justify-between border-t border-slate-50 pt-3">
                <div className="text-slate-800 font-bold text-sm">
                  {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(doctor.price)}
                </div>
                <button className="bg-teal-600 hover:bg-teal-700 text-white text-xs font-medium px-4 py-2 rounded-lg transition-colors flex items-center gap-2 shadow-sm shadow-teal-100">
                  <Calendar size={14} />
                  Đặt khám
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { SPECIALTY_OPTIONS } from './constants';
import { MessageSquare, CalendarCheck } from 'lucide-react';

function App() {
  const [activeTab, setActiveTab] = useState<'chat' | 'doctors'>('chat');
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');

  // Simple logic to parse the AI response for specialty keywords to auto-filter the doctor list
  const handleSpecialtyDetection = (text: string) => {
    // Look for exact matches of specialties in the text
    for (const spec of SPECIALTY_OPTIONS) {
      if (text.includes(spec)) {
        setSuggestedFilter(spec);
        // On mobile, show a toast or notification? 
        // For now, we update the state so when they switch tabs, it's filtered.
        break;
      }
    }
  };

  return (
    <div className="h-full flex flex-col bg-slate-100">
      {/* Mobile Header / Tab Switcher (Only visible on small screens) */}
      <div className="lg:hidden bg-white border-b border-slate-200 p-2 flex justify-around shadow-sm z-20">
        <button
          onClick={() => setActiveTab('chat')}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors
            ${activeTab === 'chat' ? 'bg-teal-50 text-teal-700' : 'text-slate-500'}`}
        >
          <MessageSquare size={18} />
          Trợ Lý AI
        </button>
        <button
          onClick={() => setActiveTab('doctors')}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors
            ${activeTab === 'doctors' ? 'bg-teal-50 text-teal-700' : 'text-slate-500'}`}
        >
          <CalendarCheck size={18} />
          Bác Sĩ
        </button>
      </div>

      <div className="flex-1 container mx-auto max-w-7xl p-0 sm:p-4 lg:p-6 h-full overflow-hidden">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">

          {/* Left Column: Chat Interface */}
          <div className={`
            lg:col-span-7 xl:col-span-8 h-full
            ${activeTab === 'chat' ? 'block' : 'hidden lg:block'}
          `}>
            <ChatInterface onSpecialtyDetected={handleSpecialtyDetection} />
          </div>

          {/* Right Column: Doctor List */}
          <div className={`
            lg:col-span-5 xl:col-span-4 h-full
            ${activeTab === 'doctors' ? 'block' : 'hidden lg:block'}
          `}>
             {/* Note for desktop users */}
             <div className="hidden lg:block mb-4 p-3 bg-teal-50 border border-teal-100 rounded-lg text-xs text-teal-800">
                <p className="font-medium mb-1">💡 Mẹo:</p>
                Sau khi AI sàng lọc, danh sách bác sĩ bên dưới sẽ tự động gợi ý chuyên khoa phù hợp.
             </div>
            <DoctorList initialFilter={suggestedFilter} key={suggestedFilter} />
          </div>

        </div>
      </div>
    </div>
  );
}

export default App;

export interface Message {
