  error: string | null;
}

import { GoogleGenAI, ChatSession, GenerativeModel } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let chatSession: ChatSession | null = null;

export const initializeChat = async () => {
  try {
    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.6, // Slightly lower for more focused medical routing
        topK: 40,
        topP: 0.95,
      },
    });
    return true;
  } catch (error) {
    console.error("Failed to initialize chat:", error);
    return false;
  }
};

interface GeminiResponse {
  text: string;
  recommendedDoctorIds?: string[];
}

export const sendMessageToGemini = async (message: string): Promise<GeminiResponse> => {
  if (!chatSession) {
    await initializeChat();
  }

  if (!chatSession) {
    throw new Error("Chat session could not be initialized.");
  }

  try {
    const response = await chatSession.sendMessage({ message });
    let text = response.text || "Xin lỗi, tôi gặp sự cố khi xử lý phản hồi. Vui lòng thử lại.";
    let recommendedDoctorIds: string[] | undefined;

    // Extract JSON block for doctor recommendations
    const jsonMatch = text.match(/```json\s*(\{[\s\S]*?\})\s*```/);
    if (jsonMatch) {
      try {
        const data = JSON.parse(jsonMatch[1]);
        if (data.recommended_doctor_ids && Array.isArray(data.recommended_doctor_ids)) {
          recommendedDoctorIds = data.recommended_doctor_ids;
        }
        // Remove the JSON block from the display text
        text = text.replace(jsonMatch[0], '').trim();
      } catch (e) {
        console.error("Failed to parse recommendation JSON", e);
      }
    }

    return { text, recommendedDoctorIds };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Không thể kết nối với hệ thống AI.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Loader2, AlertTriangle, Calendar, Star, MapPin, Clock } from 'lucide-react';
import { Message, Doctor } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import { MOCK_DOCTORS } from '../constants';

interface ChatInterfaceProps {
  onSpecialtyDetected?: (text: string) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onSpecialtyDetected }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'init-1',
      role: 'model',
      text: "Xin chào, tôi là trợ lý y tế AI.\nĐể bắt đầu sàng lọc, vui lòng cho tôi biết **triệu chứng khó chịu nhất** hiện tại của bạn là gì?",
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const { text, recommendedDoctorIds } = await sendMessageToGemini(userMessage.text);

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text,
        timestamp: new Date(),
        recommendedDoctorIds: recommendedDoctorIds
      };

      setMessages(prev => [...prev, botMessage]);

      if (onSpecialtyDetected) {
          onSpecialtyDetected(text);
      }

    } catch (error) {
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Xin lỗi, đã có lỗi xảy ra khi kết nối. Vui lòng thử lại sau.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
