import { Message, Doctor } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import { MOCK_DOCTORS } from '../constants';

interface ChatInterfaceProps {
  onSpecialtyDetected?: (text: string) => void;
  onBook: (doctor: Doctor) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onSpecialtyDetected, onBook }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'init-1',
      role: 'model',
      text: "Xin chào, tôi là trợ lý y tế AI.\nĐể bắt đầu sàng lọc, vui lòng cho tôi biết **triệu chứng khó chịu nhất** hiện tại của bạn là gì?",
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const { text, recommendedDoctorIds } = await sendMessageToGemini(userMessage.text);

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text,
        timestamp: new Date(),
        recommendedDoctorIds: recommendedDoctorIds
      };

      setMessages(prev => [...prev, botMessage]);

      if (onSpecialtyDetected) {
          onSpecialtyDetected(text);
      }

    } catch (error) {
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Xin lỗi, đã có lỗi xảy ra khi kết nối. Vui lòng thử lại sau.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const renderText = (text: string) => {
    return text.split('\n').map((line, i) => {
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <div key={i} className={`min-h-[1.4em] ${line.trim().startsWith('-') ? 'ml-4' : ''}`}>
           {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={j} className="font-bold text-slate-800">{part.slice(2, -2)}</strong>;
              }
              return <span key={j}>{part}</span>;
           })}
        </div>
      );
    });
  };

  // Mini Doctor Card for Chat
  const RecommendedDoctorCard = ({ doctorId }: { doctorId: string }) => {
    const doctor = MOCK_DOCTORS.find(d => d.id === doctorId);
    if (!doctor) return null;

    return (
      <div className="mt-3 bg-white p-3 rounded-xl border border-teal-100 shadow-sm flex flex-col gap-2 max-w-[280px]">
        <div className="flex gap-3">
            <img src={doctor.image} alt={doctor.name} className="w-10 h-10 rounded-full object-cover border border-slate-100" />
            <div className="flex-1 min-w-0">
                <p className="font-bold text-slate-800 text-sm truncate">{doctor.name}</p>
                <p className="text-teal-600 text-xs truncate">{doctor.specialty}</p>
            </div>
        </div>
        <div className="flex items-center gap-1.5 text-xs text-slate-500 bg-slate-50 p-2 rounded-lg">
            <Clock size={12} className="text-green-600" />
            <span>Trống: <span className="font-medium text-green-700">{doctor.nextAvailable}</span></span>
        </div>
        <button 
          onClick={() => onBook(doctor)}
          className="w-full bg-teal-600 hover:bg-teal-700 text-white text-xs font-semibold py-2 rounded-lg transition-colors flex items-center justify-center gap-2"
        >
            <Calendar size={14} />
            Đặt lịch ngay
        </button>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden relative">

      {/* Soft Header */}
      <div className="bg-gradient-to-r from-teal-50 to-white p-4 border-b border-slate-100 flex items-center justify-between z-10">
        <div className="flex items-center gap-3">
          <div className="bg-teal-100 p-2 rounded-2xl">
            <Bot size={24} className="text-teal-700" />
          </div>
          <div>
            <h2 className="font-bold text-slate-800 leading-tight">Trợ Lý Sức Khỏe</h2>
            <div className="flex items-center gap-1.5">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-xs text-slate-500 font-medium">Đang trực tuyến</span>
            </div>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-1.5 px-3 py-1 bg-amber-50 rounded-full border border-amber-100">
           <AlertTriangle size={12} className="text-amber-500" />
           <p className="text-[10px] text-amber-700 font-medium uppercase tracking-wide">Sàng lọc, không chẩn đoán</p>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30 scroll-smooth">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 sm:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            {/* Avatar */}
            <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-full flex items-center justify-center shrink-0 shadow-sm border
                ${msg.role === 'user' ? 'bg-blue-600 border-blue-600' : 'bg-white border-white'}`}>
              {msg.role === 'user' ? 
                <User size={16} className="text-white" /> : 
                <img src="https://cdn-icons-png.flaticon.com/512/4712/4712035.png" alt="AI" className="w-full h-full object-cover rounded-full" />
              }
            </div>

            <div className="flex flex-col gap-1 max-w-[85%] sm:max-w-[75%]">
                {/* Bubble */}
                <div
                className={`px-5 py-3.5 shadow-sm text-sm sm:text-[15px] leading-relaxed
                    ${msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-2xl rounded-tr-sm' 
                    : 'bg-white text-slate-600 border border-slate-100 rounded-2xl rounded-tl-sm'}`}
                >
                {renderText(msg.text)}
                </div>

                {/* Recommendations (if any) */}
                {msg.recommendedDoctorIds && msg.recommendedDoctorIds.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-1 animate-fade-in-up">
                        {msg.recommendedDoctorIds.map(id => (
                            <RecommendedDoctorCard key={id} doctorId={id} />
                        ))}
                    </div>
                )}

                {/* Timestamp */}
                <div className={`text-[10px] opacity-50 px-1
                    ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-4">
             <div className="w-10 h-10 rounded-full bg-white border border-slate-100 flex items-center justify-center shrink-0 shadow-sm">
                 <img src="https://cdn-icons-png.flaticon.com/512/4712/4712035.png" alt="AI" className="w-full h-full object-cover rounded-full opacity-50" />
            </div>
            <div className="bg-white border border-slate-100 rounded-2xl rounded-tl-sm px-5 py-4 shadow-sm flex items-center gap-3">
              <div className="flex gap-1">
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></span>
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></span>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white/80 backdrop-blur-md border-t border-slate-100">
        <div className="relative max-w-4xl mx-auto">
          <input
            ref={inputRef}
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Nhập triệu chứng của bạn tại đây..."
            disabled={isLoading}
            className="w-full bg-slate-50 border-0 text-slate-800 rounded-2xl pl-5 pr-14 py-4 shadow-inner ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500 focus:outline-none transition-all placeholder-slate-400 disabled:opacity-60"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputText.trim() || isLoading}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-teal-600 text-white rounded-xl hover:bg-teal-700 active:scale-95 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all shadow-md shadow-teal-200"
          >
            {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} />}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { SPECIALTY_OPTIONS } from './constants';
import { MessageSquare, Stethoscope, X, CheckCircle, Calendar, Clock, MapPin } from 'lucide-react';
import { Doctor } from './types';

function App() {
  const [activeTab, setActiveTab] = useState<'chat' | 'doctors'>('chat');
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');

  // Booking Modal State
  const [selectedDoctorForBooking, setSelectedDoctorForBooking] = useState<Doctor | null>(null);
  const [bookingSuccess, setBookingSuccess] = useState(false);

  // Simple logic to parse the AI response for specialty keywords to auto-filter the doctor list
  const handleSpecialtyDetection = (text: string) => {
    // Look for exact matches of specialties in the text
    for (const spec of SPECIALTY_OPTIONS) {
      if (text.includes(spec)) {
        setSuggestedFilter(spec);
        break;
      }
    }
  };

  const handleOpenBooking = (doctor: Doctor) => {
    setSelectedDoctorForBooking(doctor);
    setBookingSuccess(false);
  };

  const handleCloseBooking = () => {
    setSelectedDoctorForBooking(null);
    setBookingSuccess(false);
  };

  const handleConfirmBooking = (e: React.FormEvent) => {
    e.preventDefault();
    // In a real app, this would be an API call
    setBookingSuccess(true);
    // Auto close after 2 seconds
    setTimeout(() => {
        handleCloseBooking();
    }, 2500);
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 relative">

      {/* Mobile Tab Switcher */}
      <div className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 p-2 flex justify-around shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-40 safe-area-bottom">
        <button
          onClick={() => setActiveTab('chat')}
          className={`flex flex-col items-center gap-1 px-6 py-2 rounded-2xl transition-all duration-300
            ${activeTab === 'chat' ? 'text-teal-600 bg-teal-50' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <MessageSquare size={20} className={activeTab === 'chat' ? 'fill-current' : ''} />
          <span className="text-[10px] font-bold">Trợ Lý AI</span>
        </button>
        <button
          onClick={() => setActiveTab('doctors')}
          className={`flex flex-col items-center gap-1 px-6 py-2 rounded-2xl transition-all duration-300
            ${activeTab === 'doctors' ? 'text-teal-600 bg-teal-50' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <Stethoscope size={20} />
          <span className="text-[10px] font-bold">Bác Sĩ</span>
        </button>
      </div>

      <div className="flex-1 container mx-auto max-w-[1400px] p-0 sm:p-4 lg:p-6 h-full overflow-hidden">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full pb-[70px] lg:pb-0">

          {/* Left Column: Chat Interface */}
          <div className={`
            lg:col-span-8 xl:col-span-8 h-full transition-all duration-500 ease-in-out
            ${activeTab === 'chat' ? 'block opacity-100 translate-x-0' : 'hidden lg:block opacity-0 lg:opacity-100 -translate-x-full lg:translate-x-0'}
          `}>
            <ChatInterface 
                onSpecialtyDetected={handleSpecialtyDetection} 
                onBook={handleOpenBooking}
            />
          </div>

          {/* Right Column: Doctor List */}
          <div className={`
            lg:col-span-4 xl:col-span-4 h-full transition-all duration-500 ease-in-out
            ${activeTab === 'doctors' ? 'block opacity-100 translate-x-0' : 'hidden lg:block opacity-0 lg:opacity-100 translate-x-full lg:translate-x-0'}
          `}>
            <DoctorList 
                initialFilter={suggestedFilter} 
                key={suggestedFilter}
                onBook={handleOpenBooking}
            />
          </div>

        </div>
      </div>

      {/* Booking Modal Overlay */}
      {selectedDoctorForBooking && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-fade-in">
           <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-scale-up">

              {/* Modal Header */}
              <div className="bg-teal-600 p-4 flex items-center justify-between text-white">
                 <h3 className="font-bold text-lg">Xác Nhận Đặt Khám</h3>
                 <button onClick={handleCloseBooking} className="p-1 hover:bg-white/20 rounded-full transition-colors">
                    <X size={20} />
                 </button>
              </div>

              {/* Modal Body */}
              <div className="p-6">
                 {bookingSuccess ? (
                    <div className="flex flex-col items-center justify-center py-6 text-center">
                       <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                          <CheckCircle size={40} />
                       </div>
                       <h4 className="font-bold text-xl text-slate-800 mb-2">Đặt Lịch Thành Công!</h4>
                       <p className="text-slate-500 text-sm">Hệ thống đã ghi nhận lịch hẹn của bạn với <br/> <strong>{selectedDoctorForBooking.name}</strong>.</p>
                    </div>
                 ) : (
                    <>
                       {/* Doctor Summary */}
                       <div className="flex gap-4 mb-6 bg-slate-50 p-3 rounded-xl border border-slate-100">
                          <img 
                            src={selectedDoctorForBooking.image} 
                            alt={selectedDoctorForBooking.name} 
                            className="w-14 h-14 rounded-full object-cover border border-slate-200"
                          />
                          <div>
                             <p className="font-bold text-slate-800 text-sm">{selectedDoctorForBooking.name}</p>
                             <p className="text-teal-600 text-xs font-medium mb-1">{selectedDoctorForBooking.specialty}</p>
                             <div className="flex items-center gap-1 text-xs text-slate-500">
                                <Clock size={12} />
                                <span>{selectedDoctorForBooking.nextAvailable}</span>
                             </div>
                          </div>
                       </div>

                       {/* Simple Form */}
                       <form onSubmit={handleConfirmBooking} className="space-y-4">
                          <div>
                             <label className="block text-xs font-semibold text-slate-700 mb-1.5 uppercase">Họ và tên</label>
                             <input type="text" required className="w-full px-4 py-2.5 rounded-xl border border-slate-300 focus:outline-none focus:ring-2 focus:ring-teal-500 text-sm" placeholder="Nhập họ tên của bạn" />
                          </div>
                          <div>
                             <label className="block text-xs font-semibold text-slate-700 mb-1.5 uppercase">Số điện thoại</label>
                             <input type="tel" required className="w-full px-4 py-2.5 rounded-xl border border-slate-300 focus:outline-none focus:ring-2 focus:ring-teal-500 text-sm" placeholder="Nhập số điện thoại" />
                          </div>

                          <button type="submit" className="w-full bg-slate-900 hover:bg-teal-600 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-slate-200 mt-2">
                             Xác Nhận Đặt Lịch
                          </button>
                       </form>
                       <p className="text-center text-[10px] text-slate-400 mt-4">
                          Bằng việc đặt lịch, bạn đồng ý với điều khoản sử dụng của chúng tôi.
                       </p>
                    </>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
}

export default App;

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  recommendedDoctorIds?: string[];
}

export enum Specialty {
  GENERAL = 'Đa khoa',
  ENT = 'Tai Mũi Họng',
  DERMATOLOGY = 'Da liễu',
  PEDIATRICS = 'Nhi khoa',
  CARDIOLOGY = 'Tim mạch',
  NEUROLOGY = 'Thần kinh',
  GASTROENTEROLOGY = 'Tiêu hóa',
  RESPIRATORY = 'Hô hấp'
}

export interface Doctor {
  id: string;
  name: string;
  specialty: Specialty;
  experience: number;
  rating: number;
  nextAvailable: string;
  price: number;
  image: string;
}

export interface User {
  username: string;
  phone: string;
  fullName: string;
}

export interface Booking {
  id: string;
  doctorId: string;
  doctorName: string;
  doctorImage: string;
  specialty: string;
  date: string;
  status: 'Chờ khám' | 'Đã hoàn thành' | 'Đã hủy';
  timestamp: Date;
}

import React, { useState, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { 
  Home as HomeIcon, 
  MessageSquare, 
  Stethoscope, 
  History, 
  User as UserIcon,
  LogOut,
  ChevronRight,
  ShieldCheck,
  Activity,
  Calendar,
  Phone,
  Lock,
  X,
  CheckCircle
} from 'lucide-react';
import { Doctor, User, Booking } from './types';
import { MOCK_DOCTORS } from './constants';

type Page = 'home' | 'chat' | 'doctors' | 'history' | 'login';

function App() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');

  // Auth Form State
  const [authData, setAuthData] = useState({ username: '', password: '', phone: '', fullName: '' });
  const [isSignUp, setIsSignUp] = useState(false);

  // Booking Modal State
  const [pendingDoctor, setPendingDoctor] = useState<Doctor | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingSuccess, setBookingSuccess] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Giả lập đăng nhập
    const newUser = { 
      username: authData.username || 'user123', 
      phone: authData.phone || '0901234567', 
      fullName: authData.fullName || 'Nguyễn Văn Người Dùng' 
    };
    setUser(newUser);

    // Nếu đang có bác sĩ đợi đặt lịch thì quay lại trang đặt lịch
    if (pendingDoctor) {
      setCurrentPage('doctors');
      setShowBookingModal(true);
    } else {
      setCurrentPage('home');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const handleBook = (doctor: Doctor) => {
    if (!user) {
      setPendingDoctor(doctor);
      setCurrentPage('login');
      return;
    }
    setPendingDoctor(doctor);
    setShowBookingModal(true);
  };

  const confirmBooking = () => {
    if (!pendingDoctor) return;

    const newBooking: Booking = {
      id: Math.random().toString(36).substr(2, 9),
      doctorId: pendingDoctor.id,
      doctorName: pendingDoctor.name,
      doctorImage: pendingDoctor.image,
      specialty: pendingDoctor.specialty,
      date: pendingDoctor.nextAvailable,
      status: 'Chờ khám',
      timestamp: new Date()
    };

    setBookings([newBooking, ...bookings]);
    setBookingSuccess(true);
    setTimeout(() => {
      setShowBookingModal(false);
      setBookingSuccess(false);
      setPendingDoctor(null);
      setCurrentPage('history');
    }, 2000);
  };

  const renderHome = () => (
    <div className="animate-fade-in space-y-12 pb-20">
      {/* Hero Section */}
      <section className="relative overflow-hidden rounded-[2rem] bg-gradient-to-br from-teal-600 to-cyan-700 p-8 sm:p-12 text-white shadow-2xl shadow-teal-200/50">
        <div className="relative z-10 max-w-2xl">
          <div className="inline-flex items-center gap-2 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold mb-6">
            <ShieldCheck size={14} /> CÔNG NGHỆ Y TẾ AI HÀNG ĐẦU
          </div>
          <h1 className="text-4xl sm:text-5xl font-extrabold mb-6 leading-[1.1]">Sức Khỏe Của Bạn, <br/>Trách Nhiệm Của AI.</h1>
          <p className="text-teal-50/80 text-lg mb-8">Sàng lọc triệu chứng thông minh và kết nối trực tiếp với đội ngũ bác sĩ chuyên khoa đầu ngành.</p>
          <div className="flex flex-wrap gap-4">
            <button onClick={() => setCurrentPage('chat')} className="bg-white text-teal-700 hover:bg-teal-50 px-8 py-4 rounded-2xl font-bold transition-all shadow-lg flex items-center gap-2">
              Bắt đầu Sàng lọc AI <ChevronRight size={18} />
            </button>
            <button onClick={() => setCurrentPage('doctors')} className="bg-teal-500/30 backdrop-blur-md text-white border border-white/30 hover:bg-white/10 px-8 py-4 rounded-2xl font-bold transition-all">
              Xem Danh sách Bác sĩ
            </button>
          </div>
        </div>
        <div className="absolute right-[-10%] bottom-[-10%] opacity-20 pointer-events-none">
          <Activity size={400} />
        </div>
      </section>

      {/* Services */}
      <section className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { icon: <MessageSquare className="text-blue-500" />, title: 'Tư vấn AI 24/7', desc: 'Sàng lọc triệu chứng mọi lúc mọi nơi với độ chính xác cao.' },
          { icon: <Stethoscope className="text-teal-500" />, title: 'Chuyên khoa Đa dạng', desc: 'Từ Da liễu, Nhi khoa đến Tim mạch, chúng tôi có đủ.' },
          { icon: <History className="text-purple-500" />, title: 'Quản lý Lịch hẹn', desc: 'Theo dõi lịch sử khám bệnh và nhắc lịch tự động.' }
