                       <div className="flex justify-between items-center mb-6">
                          <h3 className="text-xl font-extrabold text-slate-800">Thông Tin Đặt Lịch</h3>
                          <button onClick={() => setShowBookingModal(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20}/></button>
                       </div>

                       <div className="bg-slate-50 rounded-3xl p-5 mb-8 border border-slate-100">
                          <div className="flex gap-4 mb-4">
                             <img src={pendingDoctor.image} alt={pendingDoctor.name} className="w-16 h-16 rounded-2xl object-cover border border-white shadow-sm" />
                             <div>
                                <h4 className="font-bold text-slate-800">{pendingDoctor.name}</h4>
                                <p className="text-teal-600 text-xs font-bold">{pendingDoctor.specialty}</p>
                                <div className="flex items-center gap-1.5 mt-1 text-[11px] text-slate-400 font-medium">
                                   <MapPin size={10} /> {pendingDoctor.experience} năm kinh nghiệm
                                </div>
                             </div>
                          </div>
                          <div className="flex flex-col gap-2 pt-4 border-t border-slate-200/50">
                             <div className="flex justify-between text-sm">
                                <span className="text-slate-500">Ngày khám:</span>
                                <span className="font-bold text-slate-800">{pendingDoctor.nextAvailable}</span>
                             </div>
                             <div className="flex justify-between text-sm">
                                <span className="text-slate-500">Phí dịch vụ:</span>
                                <span className="font-bold text-teal-600">{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(pendingDoctor.price)}</span>
                             </div>
                          </div>
                       </div>

                       <div className="space-y-4">
                          <div className="p-4 bg-teal-50 rounded-2xl border border-teal-100">
                             <p className="text-[10px] text-teal-700 font-bold uppercase mb-1">Xác nhận thông tin bệnh nhân</p>
                             <p className="font-bold text-slate-800">{user?.fullName}</p>
                             <p className="text-xs text-slate-500">SĐT: {user?.phone}</p>
                          </div>
                          <button onClick={confirmBooking} className="w-full bg-teal-600 hover:bg-teal-700 text-white font-extrabold py-4 rounded-2xl shadow-xl shadow-teal-100 transition-all active:scale-95">
                             Xác Nhận & Đặt Ngay
                          </button>
                       </div>
                    </>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
}

