  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const newUser = { 
      username: authData.username || 'user_demo', 
      phone: authData.phone || '0901234567', 
      fullName: authData.fullName || 'Nguyễn Văn Khách' 
    };
    setUser(newUser);
