export default App;

import { 
  collection, 
  getDocs, 
  addDoc, 
  query, 
  where, 
  orderBy,
  Timestamp 
} from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { db } from "../firebaseConfig";
import { Doctor, Booking } from "../types";
import { MOCK_DOCTORS } from "../constants";

// Helper để lưu local nếu Firebase lỗi
const saveBookingLocal = (bookingData: any) => {
  const localBookings = JSON.parse(localStorage.getItem('care_ai_bookings') || '[]');
  const newBooking = {
    ...bookingData,
    id: 'local_' + Math.random().toString(36).substr(2, 9),
    timestamp: new Date()
  };
  localStorage.setItem('care_ai_bookings', JSON.stringify([newBooking, ...localBookings]));
  return newBooking.id;
};

const getBookingsLocal = (phone: string): Booking[] => {
  const localBookings = JSON.parse(localStorage.getItem('care_ai_bookings') || '[]');
  return localBookings.filter((b: any) => b.userPhone === phone);
};

// Lấy danh sách bác sĩ - Fallback về MOCK_DOCTORS nếu lỗi Firebase
export const fetchDoctors = async (): Promise<Doctor[]> => {
  try {
    const querySnapshot = await getDocs(collection(db, "doctors"));
    if (querySnapshot.empty) return MOCK_DOCTORS;

    return querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    } as Doctor));
  } catch (e) {
    console.warn("Firestore error (fetchDoctors): Chuyển sang sử dụng Mock Data.", e);
    return MOCK_DOCTORS;
  }
};

// Lưu lịch hẹn - Fallback về LocalStorage nếu lỗi Firebase
export const saveBooking = async (bookingData: any) => {
  try {
    const docRef = await addDoc(collection(db, "bookings"), {
      ...bookingData,
      timestamp: Timestamp.now()
    });
    return docRef.id;
  } catch (e) {
    console.warn("Firestore error (saveBooking): Đang lưu tạm vào LocalStorage.", e);
    return saveBookingLocal(bookingData);
  }
};

// Lấy lịch sử khám - Gộp dữ liệu từ Firebase và LocalStorage
export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  let firebaseBookings: Booking[] = [];
  try {
    const q = query(
      collection(db, "bookings"), 
      where("userPhone", "==", phone),
      orderBy("timestamp", "desc")
    );
    const querySnapshot = await getDocs(q);
    firebaseBookings = querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data(),
      timestamp: doc.data().timestamp?.toDate() || new Date()
    } as Booking));
  } catch (e) {
    console.warn("Firestore error (fetchUserBookings): Không thể lấy dữ liệu từ Cloud.", e);
  }

  const localOnes = getBookingsLocal(phone);
  // Kết hợp và lọc trùng
  const combined = [...firebaseBookings, ...localOnes].sort((a, b) => 
    new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
  );

  return combined;
};

import React, { useState, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { 
  Home as HomeIcon, 
  MessageSquare, 
  Stethoscope, 
  History, 
  User as UserIcon,
  LogOut,
  ChevronRight,
  ShieldCheck,
  Activity,
  Calendar,
  Phone,
  Lock,
  X,
  CheckCircle,
  MapPin,
  Clock,
  ArrowRight,
  Loader2,
  WifiOff
} from 'lucide-react';
import { Doctor, User, Booking } from './types';
import { fetchDoctors, saveBooking, fetchUserBookings } from './services/databaseService';
import { MOCK_DOCTORS } from './constants';

type Page = 'home' | 'chat' | 'doctors' | 'history' | 'login';

function App() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [doctors, setDoctors] = useState<Doctor[]>(MOCK_DOCTORS);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');
  const [loading, setLoading] = useState(true);
  const [isCloudError, setIsCloudError] = useState(false);

  // Auth Form State
  const [authData, setAuthData] = useState({ username: '', password: '', phone: '', fullName: '' });
  const [isSignUp, setIsSignUp] = useState(false);

  // Booking Modal State
  const [pendingDoctor, setPendingDoctor] = useState<Doctor | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingSuccess, setBookingSuccess] = useState(false);
  const [isSubmittingBooking, setIsSubmittingBooking] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const initApp = async () => {
      try {
        const docs = await fetchDoctors();
        setDoctors(docs);

        const savedUser = localStorage.getItem('care_ai_user');
        if (savedUser) {
          const parsedUser = JSON.parse(savedUser);
          setUser(parsedUser);
          const userHistory = await fetchUserBookings(parsedUser.phone);
          setBookings(userHistory);
        }
      } catch (error) {
        console.error("Lỗi khởi tạo ứng dụng:", error);
        setIsCloudError(true);
      } finally {
        // Luôn cho phép vào app sau 1s dù cloud có lỗi
        setTimeout(() => setLoading(false), 1000);
      }
    };
    initApp();
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    const newUser = { 
      username: authData.username || 'user_demo', 
      phone: authData.phone || '0901234567', 
      fullName: authData.fullName || 'Người dùng mới' 
    };
    setUser(newUser);
    localStorage.setItem('care_ai_user', JSON.stringify(newUser));

    // Refresh history
    const history = await fetchUserBookings(newUser.phone);
    setBookings(history);

    if (pendingDoctor) {
      setCurrentPage('doctors');
      setShowBookingModal(true);
    } else {
      setCurrentPage('home');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setBookings([]);
    localStorage.removeItem('care_ai_user');
    setCurrentPage('home');
  };

  const handleBook = (doctor: Doctor) => {
    if (!user) {
      setPendingDoctor(doctor);
      setCurrentPage('login');
      return;
    }
    setPendingDoctor(doctor);
    setShowBookingModal(true);
  };

  const confirmBooking = async () => {
    if (!pendingDoctor || !user) return;

    setIsSubmittingBooking(true);
    try {
      const bookingData = {
        doctorId: pendingDoctor.id,
        doctorName: pendingDoctor.name,
        doctorImage: pendingDoctor.image,
        specialty: pendingDoctor.specialty,
        date: pendingDoctor.nextAvailable,
        userPhone: user.phone,
        userFullName: user.fullName,
        status: 'Chờ khám'
      };

      await saveBooking(bookingData);

      const updatedHistory = await fetchUserBookings(user.phone);
      setBookings(updatedHistory);

      setBookingSuccess(true);
      setTimeout(() => {
        setShowBookingModal(false);
        setBookingSuccess(false);
        setPendingDoctor(null);
        setCurrentPage('history');
      }, 2000);
    } catch (error) {
      alert("Lỗi: Không thể lưu lịch hẹn. Vui lòng thử lại.");
    } finally {
      setIsSubmittingBooking(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <div className="relative">
          <Loader2 size={64} className="text-teal-600 animate-spin" />
