import { initializeApp } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js";
import { getFirestore } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { getAuth } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

// THAY THẾ CÁC GIÁ TRỊ DƯỚI ĐÂY BẰNG CONFIG CỦA BẠN TỪ FIREBASE CONSOLE
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "YOUR_PROJECT_ID.firebaseapp.com",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_PROJECT_ID.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// Kiểm tra xem người dùng đã điền thông tin thật chưa
export const isFirebaseConfigured = 
  firebaseConfig.projectId !== "YOUR_PROJECT_ID" && 
  firebaseConfig.apiKey !== "YOUR_API_KEY";

const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);
export const auth = getAuth(app);

import { 
  collection, 
  getDocs, 
  addDoc, 
  query, 
  where, 
  orderBy,
  Timestamp 
} from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { db, isFirebaseConfigured } from "../firebaseConfig";
import { Doctor, Booking } from "../types";
import { MOCK_DOCTORS } from "../constants";

// --- LOCAL STORAGE FALLBACK LOGIC ---

const saveBookingLocal = (bookingData: any) => {
  const localBookings = JSON.parse(localStorage.getItem('care_ai_bookings') || '[]');
  const newBooking = {
    ...bookingData,
    id: 'local_' + Math.random().toString(36).substr(2, 9),
    timestamp: new Date()
  };
  localStorage.setItem('care_ai_bookings', JSON.stringify([newBooking, ...localBookings]));
  return newBooking.id;
};

const getBookingsLocal = (phone: string): Booking[] => {
  const localBookings = JSON.parse(localStorage.getItem('care_ai_bookings') || '[]');
  return localBookings.filter((b: any) => b.userPhone === phone).map((b: any) => ({
    ...b,
    timestamp: new Date(b.timestamp)
  }));
};

// --- EXPORTED SERVICE FUNCTIONS ---

export const fetchDoctors = async (): Promise<Doctor[]> => {
  if (!isFirebaseConfigured) {
    console.warn("CareAI: Firebase chưa được cấu hình. Sử dụng dữ liệu mẫu.");
    return MOCK_DOCTORS;
  }

  try {
    const querySnapshot = await getDocs(collection(db, "doctors"));
    if (querySnapshot.empty) return MOCK_DOCTORS;

    return querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    } as Doctor));
  } catch (e) {
    console.error("Firestore error (fetchDoctors):", e);
    return MOCK_DOCTORS;
  }
};

export const saveBooking = async (bookingData: any) => {
  if (!isFirebaseConfigured) {
    return saveBookingLocal(bookingData);
  }

  try {
    const docRef = await addDoc(collection(db, "bookings"), {
      ...bookingData,
      timestamp: Timestamp.now()
    });
    return docRef.id;
  } catch (e) {
    console.error("Firestore error (saveBooking):", e);
    return saveBookingLocal(bookingData);
  }
};

export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  const localOnes = getBookingsLocal(phone);

  if (!isFirebaseConfigured) {
    return localOnes;
  }

  try {
    const q = query(
      collection(db, "bookings"), 
      where("userPhone", "==", phone),
      orderBy("timestamp", "desc")
    );
    const querySnapshot = await getDocs(q);
    const firebaseBookings = querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data(),
      timestamp: doc.data().timestamp?.toDate() || new Date()
    } as Booking));

    // Gộp và lọc trùng dựa trên nội dung nếu cần (đơn giản là gộp)
    const combined = [...firebaseBookings, ...localOnes].sort((a, b) => 
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
    return combined;
  } catch (e) {
    console.error("Firestore error (fetchUserBookings):", e);
    return localOnes;
  }
};

