export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onSpecialtyDetected, onBook }) => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'init-1',
      role: 'model',
      text: "Xin chào, tôi là trợ lý y tế AI.\nĐể bắt đầu, vui lòng cho tôi biết **triệu chứng khó chịu nhất** của bạn là gì?",
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const { text, recommendedDoctorIds } = await sendMessageToGemini(userMessage.text);

      const botMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text,
        timestamp: new Date(),
        recommendedDoctorIds: recommendedDoctorIds
      };

      setMessages(prev => [...prev, botMessage]);

      if (onSpecialtyDetected) {
          onSpecialtyDetected(text);
      }

    } catch (error) {
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Xin lỗi, đã có lỗi xảy ra khi kết nối. Vui lòng thử lại sau.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const renderText = (text: string) => {
    return text.split('\n').map((line, i) => {
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <div key={i} className={`min-h-[1.4em] ${line.trim().startsWith('-') ? 'ml-4' : ''}`}>
           {parts.map((part, j) => {
              if (part.startsWith('**') && part.endsWith('**')) {
                return <strong key={j} className="font-bold text-slate-800">{part.slice(2, -2)}</strong>;
              }
              return <span key={j}>{part}</span>;
           })}
        </div>
      );
    });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden relative">

      {/* Soft Header */}
      <div className="bg-gradient-to-r from-teal-50 to-white p-4 border-b border-slate-100 flex items-center justify-between z-10">
        <div className="flex items-center gap-3">
          <div className="bg-teal-100 p-2 rounded-2xl">
            <Bot size={24} className="text-teal-700" />
          </div>
          <div>
            <h2 className="font-bold text-slate-800 leading-tight">Trợ Lý Sức Khỏe</h2>
            <div className="flex items-center gap-1.5">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-xs text-slate-500 font-medium">Đang trực tuyến</span>
            </div>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-1.5 px-3 py-1 bg-amber-50 rounded-full border border-amber-100">
           <AlertTriangle size={12} className="text-amber-500" />
           <p className="text-[10px] text-amber-700 font-medium uppercase tracking-wide">Sàng lọc, không chẩn đoán</p>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30 scroll-smooth">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 sm:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            {/* Avatar */}
            <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-full flex items-center justify-center shrink-0 shadow-sm border
                ${msg.role === 'user' ? 'bg-blue-600 border-blue-600' : 'bg-white border-white'}`}>
              {msg.role === 'user' ? 
                <User size={16} className="text-white" /> : 
                <img src="https://cdn-icons-png.flaticon.com/512/4712/4712035.png" alt="AI" className="w-full h-full object-cover rounded-full" />
              }
            </div>

            <div className="flex flex-col gap-1 max-w-[85%] sm:max-w-[75%]">
                {/* Bubble */}
                <div
                className={`px-5 py-3.5 shadow-sm text-sm sm:text-[15px] leading-relaxed
                    ${msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-2xl rounded-tr-sm' 
                    : 'bg-white text-slate-600 border border-slate-100 rounded-2xl rounded-tl-sm'}`}
                >
                {renderText(msg.text)}
                </div>

                {/* Recommendations (if any) */}
                {msg.recommendedDoctorIds && msg.recommendedDoctorIds.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-1 animate-fade-in-up">
                        {msg.recommendedDoctorIds.map(id => (
                            <RecommendedDoctorCard key={id} doctorId={id} onBook={onBook} />
                        ))}
                    </div>
                )}

                {/* Timestamp */}
                <div className={`text-[10px] opacity-50 px-1
                    ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-4">
             <div className="w-10 h-10 rounded-full bg-white border border-slate-100 flex items-center justify-center shrink-0 shadow-sm">
                 <img src="https://cdn-icons-png.flaticon.com/512/4712/4712035.png" alt="AI" className="w-full h-full object-cover rounded-full opacity-50" />
            </div>
            <div className="bg-white border border-slate-100 rounded-2xl rounded-tl-sm px-5 py-4 shadow-sm flex items-center gap-3">
              <div className="flex gap-1">
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></span>
                <span className="w-2 h-2 bg-teal-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></span>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white/80 backdrop-blur-md border-t border-slate-100">
        <div className="relative max-w-4xl mx-auto">
          <input
            ref={inputRef}
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Nhập triệu chứng của bạn tại đây..."
            disabled={isLoading}
            className="w-full bg-slate-50 border-0 text-slate-800 rounded-2xl pl-5 pr-14 py-4 shadow-inner ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500 focus:outline-none transition-all placeholder-slate-400 disabled:opacity-60"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputText.trim() || isLoading}
            className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-teal-600 text-white rounded-xl hover:bg-teal-700 active:scale-95 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all shadow-md shadow-teal-200"
          >
            {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} />}
          </button>
        </div>
      </div>
    </div>
  );
};

import { Doctor, Booking } from "../types";
import { MOCK_DOCTORS } from "../constants";

// LOCAL STORAGE KEY
const STORAGE_KEY = 'care_ai_bookings';

// --- SERVICE HOÀN TOÀN CHẠY TRÊN TRÌNH DUYỆT (Offline-first) ---

export const fetchDoctors = async (): Promise<Doctor[]> => {
  // Giả lập độ trễ mạng cực thấp để tạo cảm giác mượt mà
  return new Promise((resolve) => {
    setTimeout(() => resolve(MOCK_DOCTORS), 100);
  });
};

export const saveBooking = async (bookingData: any) => {
  return new Promise((resolve) => {
    setTimeout(() => {
      try {
        const currentData = localStorage.getItem(STORAGE_KEY);
        const localBookings = currentData ? JSON.parse(currentData) : [];

        const newBooking = {
          ...bookingData,
          id: 'booking_' + Date.now(),
          timestamp: new Date().toISOString() // Lưu dưới dạng chuỗi ISO để an toàn
        };

        // Thêm mới vào đầu danh sách
        const updatedBookings = [newBooking, ...localBookings];

        // Lưu vĩnh viễn vào trình duyệt
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedBookings));

        console.log("Đã lưu lịch hẹn thành công:", newBooking);
        resolve(newBooking.id);
      } catch (error) {
        console.error("Lỗi lưu dữ liệu:", error);
        resolve(null);
      }
    }, 500); // Giả lập xử lý server
  });
};

export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  return new Promise((resolve) => {
    setTimeout(() => {
       try {
        const currentData = localStorage.getItem(STORAGE_KEY);
        const localBookings = currentData ? JSON.parse(currentData) : [];

        const userBookings = localBookings
          .filter((b: any) => b.userPhone === phone)
          .map((b: any) => ({
            ...b,
            // Quan trọng: Chuyển đổi chuỗi thời gian trở lại đối tượng Date để React hiển thị đúng
            timestamp: new Date(b.timestamp)
          }));

        resolve(userBookings);
       } catch (error) {
         console.error("Lỗi đọc dữ liệu:", error);
         resolve([]);
       }
    }, 300);
  });
};

export const updateBookingStatus = async (bookingId: string, newStatus: 'Chờ khám' | 'Đã hoàn thành' | 'Đã hủy'): Promise<boolean> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      try {
        const currentData = localStorage.getItem(STORAGE_KEY);
        if (!currentData) return resolve(false);

        const localBookings = JSON.parse(currentData);
        const updatedBookings = localBookings.map((b: any) => 
          b.id === bookingId ? { ...b, status: newStatus } : b
        );

        localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedBookings));
        resolve(true);
      } catch (error) {
        console.error("Lỗi cập nhật trạng thái:", error);
        resolve(false);
      }
    }, 400);
  });
};

import React, { useState, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { 
  Home as HomeIcon, 
  MessageSquare, 
  Stethoscope, 
  History, 
  User as UserIcon,
  LogOut,
  ChevronRight,
  ShieldCheck,
  Calendar,
  Phone,
  X,
  CheckCircle,
  ArrowRight,
  Loader2,
  Database,
  Trash2,
  AlertCircle
} from 'lucide-react';
import { Doctor, User, Booking } from './types';
import { fetchDoctors, saveBooking, fetchUserBookings, updateBookingStatus } from './services/databaseService';
import { MOCK_DOCTORS } from './constants';

type Page = 'home' | 'chat' | 'doctors' | 'history' | 'login';

function App() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [doctors, setDoctors] = useState<Doctor[]>(MOCK_DOCTORS);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');
  const [loading, setLoading] = useState(true);

  // Auth Form State
  const [authData, setAuthData] = useState({ username: '', password: '', phone: '', fullName: '' });

  // Booking Modal State
  const [pendingDoctor, setPendingDoctor] = useState<Doctor | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingSuccess, setBookingSuccess] = useState(false);
  const [isSubmittingBooking, setIsSubmittingBooking] = useState(false);

  // Load Initial Data
  useEffect(() => {
    const initApp = async () => {
      try {
        const docs = await fetchDoctors();
        setDoctors(docs);

        const savedUser = localStorage.getItem('care_ai_user');
        if (savedUser) {
          const parsedUser = JSON.parse(savedUser);
          setUser(parsedUser);
          const userHistory = await fetchUserBookings(parsedUser.phone);
          setBookings(userHistory);
        }
      } catch (error) {
        console.error("Lỗi khởi tạo ứng dụng:", error);
      } finally {
        setLoading(false);
      }
    };
    initApp();
  }, []);

  useEffect(() => {
    if (currentPage === 'history' && user) {
      const refreshHistory = async () => {
        const history = await fetchUserBookings(user.phone);
        setBookings(history);
      };
      refreshHistory();
    }
  }, [currentPage, user]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    const newUser = { 
      username: authData.username || 'user_demo', 
      phone: authData.phone || '0901234567', 
      fullName: authData.fullName || 'Người dùng mới' 
    };
    setUser(newUser);
    localStorage.setItem('care_ai_user', JSON.stringify(newUser));

    const history = await fetchUserBookings(newUser.phone);
    setBookings(history);

    if (pendingDoctor) {
      setCurrentPage('doctors');
      setShowBookingModal(true);
    } else {
      setCurrentPage('home');
    }
  };

  const handleLogout = () => {
    setUser(null);
    setBookings([]);
    localStorage.removeItem('care_ai_user');
    setCurrentPage('home');
  };

  const handleBook = (doctor: Doctor) => {
    if (!user) {
      setPendingDoctor(doctor);
      setCurrentPage('login');
      return;
    }
    setPendingDoctor(doctor);
    setShowBookingModal(true);
  };

  const handleViewDoctorInList = (doctor: Doctor) => {
    setSuggestedFilter(doctor.specialty);
    setCurrentPage('doctors');
  };

  const confirmBooking = async () => {
    if (!pendingDoctor || !user) return;

    setIsSubmittingBooking(true);
    try {
      const bookingData = {
        doctorId: pendingDoctor.id,
        doctorName: pendingDoctor.name,
        doctorImage: pendingDoctor.image,
        specialty: pendingDoctor.specialty,
        date: pendingDoctor.nextAvailable,
        userPhone: user.phone,
        userFullName: user.fullName,
        status: 'Chờ khám'
      };

      await saveBooking(bookingData);
      const updatedHistory = await fetchUserBookings(user.phone);
      setBookings(updatedHistory);

      setBookingSuccess(true);
      setTimeout(() => {
        setShowBookingModal(false);
        setBookingSuccess(false);
        setPendingDoctor(null);
        setCurrentPage('history');
      }, 1500);
    } catch (error) {
      alert("Đã có lỗi xảy ra khi đặt lịch. Vui lòng thử lại.");
    } finally {
      setIsSubmittingBooking(false);
    }
  };

  const handleCancelBooking = async (bookingId: string) => {
    if (!window.confirm("Bạn có chắc chắn muốn hủy lịch hẹn này không?")) return;

    const success = await updateBookingStatus(bookingId, 'Đã hủy');
    if (success && user) {
      const updatedHistory = await fetchUserBookings(user.phone);
      setBookings(updatedHistory);
    } else {
      alert("Không thể hủy lịch vào lúc này. Vui lòng thử lại.");
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 size={48} className="text-teal-600 animate-spin mb-4" />
        <p className="text-slate-500 font-bold animate-pulse">Đang tải dữ liệu...</p>
      </div>
    );
  }

  const renderHome = () => (
    <div className="animate-fade-in space-y-20 pb-20">
      <section className="relative overflow-hidden rounded-[3rem] bg-slate-900 p-8 sm:p-16 text-white shadow-2xl">
        <div className="absolute top-0 right-0 w-1/2 h-full bg-gradient-to-l from-teal-500/20 to-transparent pointer-events-none"></div>
        <div className="relative z-10 max-w-2xl">
          <div className="inline-flex items-center gap-2 bg-teal-500/20 backdrop-blur-md px-4 py-2 rounded-full text-xs font-bold mb-8 text-teal-400 border border-teal-500/30">
            <ShieldCheck size={16} /> HỆ THỐNG Y TẾ THÔNG MINH
          </div>
          <h1 className="text-5xl sm:text-7xl font-extrabold mb-8 leading-[1.05] tracking-tight">
            Chăm sóc <br/><span className="text-teal-400">tận tâm</span> bằng <br/>trí tuệ nhân tạo.
          </h1>
          <p className="text-slate-400 text-lg sm:text-xl mb-10 leading-relaxed max-w-lg">
            Sàng lọc triệu chứng chính xác, gợi ý bác sĩ chuyên khoa phù hợp và đặt lịch chỉ trong 30 giây.
          </p>
          <div className="flex flex-wrap gap-5">
            <button onClick={() => setCurrentPage('chat')} className="bg-teal-500 hover:bg-teal-400 text-slate-900 px-10 py-5 rounded-2xl font-bold transition-all shadow-xl shadow-teal-500/20 flex items-center gap-3 active:scale-95">
              Khám Phá Cùng AI <ArrowRight size={20} />
            </button>
            <button onClick={() => setCurrentPage('doctors')} className="bg-slate-800 text-white border border-slate-700 hover:bg-slate-700 px-10 py-5 rounded-2xl font-bold transition-all active:scale-95">
