import { Doctor, Booking } from "../types";
import { MOCK_DOCTORS } from "../constants";

const STORAGE_KEY_BOOKINGS = 'care_ai_bookings';
const STORAGE_KEY_DOCTORS = 'care_ai_doctors';

// --- QUẢN LÝ BÁC SĨ (CRUD) ---

export const fetchDoctors = async (): Promise<Doctor[]> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      const localDocs = localStorage.getItem(STORAGE_KEY_DOCTORS);
      if (localDocs) {
        resolve(JSON.parse(localDocs));
      } else {
        // Khởi tạo dữ liệu mẫu nếu chưa có
        localStorage.setItem(STORAGE_KEY_DOCTORS, JSON.stringify(MOCK_DOCTORS));
        resolve(MOCK_DOCTORS);
      }
    }, 100);
  });
};

export const saveDoctor = async (doctor: Doctor): Promise<void> => {
  const docs = await fetchDoctors();
  const index = docs.findIndex(d => d.id === doctor.id);
  if (index > -1) {
    docs[index] = doctor;
  } else {
    docs.push({ ...doctor, id: 'doc_' + Date.now() });
  }
  localStorage.setItem(STORAGE_KEY_DOCTORS, JSON.stringify(docs));
};

export const deleteDoctor = async (id: string): Promise<void> => {
  const docs = await fetchDoctors();
  const filtered = docs.filter(d => d.id !== id);
  localStorage.setItem(STORAGE_KEY_DOCTORS, JSON.stringify(filtered));
};

// --- QUẢN LÝ LỊCH HẸN ---

export const saveBooking = async (bookingData: any) => {
  try {
    const currentData = localStorage.getItem(STORAGE_KEY_BOOKINGS);
    const localBookings = currentData ? JSON.parse(currentData) : [];

    const newBooking = {
      ...bookingData,
      id: 'book_' + Date.now() + Math.random().toString(36).substr(2, 5),
      timestamp: new Date().toISOString()
    };

    localStorage.setItem(STORAGE_KEY_BOOKINGS, JSON.stringify([newBooking, ...localBookings]));
    return newBooking.id;
  } catch (error) {
    return null;
  }
};

export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  const currentData = localStorage.getItem(STORAGE_KEY_BOOKINGS);
  const localBookings = currentData ? JSON.parse(currentData) : [];
  return localBookings
    .filter((b: any) => b.userPhone === phone)
    .map((b: any) => ({ ...b, timestamp: new Date(b.timestamp) }));
};

// Hàm dành riêng cho Admin để xem toàn bộ lịch của mọi người
export const fetchAllBookings = async (): Promise<Booking[]> => {
  const currentData = localStorage.getItem(STORAGE_KEY_BOOKINGS);
  const localBookings = currentData ? JSON.parse(currentData) : [];
  return localBookings.map((b: any) => ({ ...b, timestamp: new Date(b.timestamp) }));
};

export const updateBookingStatus = async (bookingId: string, newStatus: string): Promise<boolean> => {
  const currentData = localStorage.getItem(STORAGE_KEY_BOOKINGS);
  if (!currentData) return false;

  const localBookings = JSON.parse(currentData);
  const updated = localBookings.map((b: any) => 
    b.id === bookingId ? { ...b, status: newStatus } : b
  );

  localStorage.setItem(STORAGE_KEY_BOOKINGS, JSON.stringify(updated));
  return true;
};

import React, { useState, useEffect } from 'react';
import { ChatInterface } from './components/ChatInterface';
import { DoctorList } from './components/DoctorList';
import { 
  Home as HomeIcon, MessageSquare, Stethoscope, History, User as UserIcon,
  LogOut, ChevronRight, ShieldCheck, Calendar, Phone, X, CheckCircle,
  ArrowRight, Loader2, Database, Trash2, Clock, Settings, Plus, Edit, Briefcase
} from 'lucide-react';
import { Doctor, User, Booking, Specialty } from './types';
import { 
  fetchDoctors, saveBooking, fetchUserBookings, updateBookingStatus, 
  fetchAllBookings, saveDoctor, deleteDoctor 
} from './services/databaseService';

type Page = 'home' | 'chat' | 'doctors' | 'history' | 'login' | 'admin';

function App() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [allBookings, setAllBookings] = useState<Booking[]>([]);
  const [suggestedFilter, setSuggestedFilter] = useState<string>('All');
  const [loading, setLoading] = useState(true);

  // Admin Form States
  const [editingDoctor, setEditingDoctor] = useState<Partial<Doctor> | null>(null);
  const [showDocModal, setShowDocModal] = useState(false);

  // User Auth & Modal States
  const [authData, setAuthData] = useState({ username: '', phone: '', isAdmin: false });
  const [pendingDoctor, setPendingDoctor] = useState<Doctor | null>(null);
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [bookingSuccess, setBookingSuccess] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const init = async () => {
      const docs = await fetchDoctors();
      setDoctors(docs);
      const savedUser = localStorage.getItem('care_ai_user');
      if (savedUser) {
        const u = JSON.parse(savedUser);
        setUser(u);
        const history = await fetchUserBookings(u.phone);
        setBookings(history);
      }
      setLoading(false);
    };
    init();
  }, []);

  // Sync data khi chuyển trang
  useEffect(() => {
    if (user) {
      if (currentPage === 'history') fetchUserBookings(user.phone).then(setBookings);
      if (currentPage === 'admin' && user.isAdmin) {
        fetchAllBookings().then(setAllBookings);
        fetchDoctors().then(setDoctors);
      }
    }
  }, [currentPage, user]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Giả lập: Nếu phone là "000" thì là admin
    const isAdmin = authData.phone === '000';
    const newUser = { ...authData, fullName: authData.username, isAdmin };
    setUser(newUser);
    localStorage.setItem('care_ai_user', JSON.stringify(newUser));
    setCurrentPage(isAdmin ? 'admin' : 'home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('care_ai_user');
    setCurrentPage('home');
  };

  const onCancelBooking = async (id: string) => {
    if (!confirm("Hủy lịch hẹn này?")) return;
    const ok = await updateBookingStatus(id, 'Đã hủy');
    if (ok) {
      if (user?.isAdmin) setAllBookings(prev => prev.map(b => b.id === id ? {...b, status: 'Đã hủy'} : b));
      setBookings(prev => prev.map(b => b.id === id ? {...b, status: 'Đã hủy'} : b));
    }
  };

  const onSaveDoctor = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDoctor) return;
    await saveDoctor(editingDoctor as Doctor);
    const updated = await fetchDoctors();
    setDoctors(updated);
    setShowDocModal(false);
    setEditingDoctor(null);
  };

  const onDeleteDoctor = async (id: string) => {
    if (!confirm("Xóa bác sĩ này?")) return;
    await deleteDoctor(id);
    setDoctors(await fetchDoctors());
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin text-teal-600" size={40} /></div>;

  return (
