import { Doctor, Booking, User } from "../types";
import { db, isFirebaseConfigured } from "../firebaseConfig";
import { 
  collection, 
  getDocs, 
  getDoc,
  doc, 
  setDoc, 
  addDoc, 
  updateDoc, 
  deleteDoc,
  query, 
  where, 
  orderBy, 
  serverTimestamp 
} from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

// --- QUẢN LÝ BÁC SĨ (Firestore) ---

export const fetchDoctors = async (): Promise<Doctor[]> => {
  if (!isFirebaseConfigured) {
    // Fallback nếu chưa cấu hình Firebase
    const local = localStorage.getItem('care_ai_doctors');
    return local ? JSON.parse(local) : [];
  }

  const querySnapshot = await getDocs(collection(db, "doctors"));
  return querySnapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  } as Doctor));
};

export const saveDoctor = async (doctor: Doctor): Promise<void> => {
  if (!isFirebaseConfigured) return;
  const docData = { ...doctor };
  const docId = doctor.id || 'doc_' + Date.now();
  delete docData.id; // ID sẽ nằm ở tên document
  await setDoc(doc(db, "doctors", docId), docData);
};

export const deleteDoctor = async (id: string): Promise<void> => {
  if (!isFirebaseConfigured) return;
  await deleteDoc(doc(db, "doctors", id));
};

// --- QUẢN LÝ NGƯỜI DÙNG ---

export const getUserProfile = async (phone: string): Promise<User | null> => {
  if (!isFirebaseConfigured) return null;
  const docRef = doc(db, "users", phone);
  const docSnap = await getDoc(docRef);
  return docSnap.exists() ? docSnap.data() as User : null;
};

export const saveUserProfile = async (user: User): Promise<void> => {
  if (!isFirebaseConfigured) return;
  await setDoc(doc(db, "users", user.phone), user);
};

// --- QUẢN LÝ LỊCH HẸN (Firestore) ---

export const saveBooking = async (bookingData: any) => {
  if (!isFirebaseConfigured) return null;
  try {
    const docRef = await addDoc(collection(db, "bookings"), {
      ...bookingData,
      timestamp: serverTimestamp(),
      status: 'Chờ khám'
    });
    return docRef.id;
  } catch (e) {
    console.error("Lỗi khi đặt lịch:", e);
    return null;
  }
};

export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  if (!isFirebaseConfigured) return [];
  const q = query(
    collection(db, "bookings"), 
    where("userPhone", "==", phone),
    orderBy("timestamp", "desc")
  );
  const querySnapshot = await getDocs(q);
  return querySnapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data(),
    timestamp: doc.data().timestamp?.toDate() || new Date()
  } as Booking));
};

export const fetchAllBookings = async (): Promise<Booking[]> => {
  if (!isFirebaseConfigured) return [];
  const q = query(collection(db, "bookings"), orderBy("timestamp", "desc"));
  const querySnapshot = await getDocs(q);
  return querySnapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data(),
    timestamp: doc.data().timestamp?.toDate() || new Date()
  } as Booking));
};

export const updateBookingStatus = async (bookingId: string, newStatus: string): Promise<boolean> => {
  if (!isFirebaseConfigured) return false;
  try {
    const docRef = doc(db, "bookings", bookingId);
    await updateDoc(docRef, { status: newStatus });
    return true;
  } catch (e) {
    return false;
  }
};

