import { Doctor, Booking, User } from "../types";
import { db, isFirebaseConfigured } from "../firebaseConfig";
import { MOCK_DOCTORS } from "../constants";
import { 
  collection, 
  getDocs, 
  getDoc,
  doc, 
  setDoc, 
  addDoc, 
  updateDoc, 
  deleteDoc,
  query, 
  where, 
  orderBy, 
  serverTimestamp 
} from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

// Helper để lấy dữ liệu từ LocalStorage nếu chưa có Firebase (cho mục đích demo)
const getLocal = (key: string) => JSON.parse(localStorage.getItem(key) || 'null');
const setLocal = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));

// --- QUẢN LÝ BÁC SĨ ---
export const fetchDoctors = async (): Promise<Doctor[]> => {
  if (!isFirebaseConfigured || !db) {
    const local = getLocal('care_ai_doctors');
    if (!local) {
      setLocal('care_ai_doctors', MOCK_DOCTORS);
      return MOCK_DOCTORS;
    }
    return local;
  }

  try {
    const querySnapshot = await getDocs(collection(db, "doctors"));
    if (querySnapshot.empty) return [];
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Doctor));
  } catch (e) {
    console.error("Firestore Fetch Error:", e);
    return [];
  }
};

export const saveDoctor = async (doctor: Doctor): Promise<void> => {
  if (!isFirebaseConfigured || !db) {
    const docs = await fetchDoctors();
    const idx = docs.findIndex(d => d.id === doctor.id);
    if (idx > -1) docs[idx] = doctor;
    else docs.push({ ...doctor, id: 'doc_' + Date.now() });
    setLocal('care_ai_doctors', docs);
    return;
  }

  const docId = doctor.id || 'doc_' + Date.now();
  const data = { ...doctor };
  delete data.id;
  await setDoc(doc(db, "doctors", docId), data);
};

export const deleteDoctor = async (id: string): Promise<void> => {
  if (!isFirebaseConfigured || !db) {
    const docs = await fetchDoctors();
    setLocal('care_ai_doctors', docs.filter(d => d.id !== id));
    return;
  }
  await deleteDoc(doc(db, "doctors", id));
};

// --- QUẢN LÝ LỊCH HẸN ---
export const saveBooking = async (bookingData: any) => {
  if (!isFirebaseConfigured || !db) {
    const local = getLocal('care_ai_bookings') || [];
    const newBooking = { ...bookingData, id: 'bk_' + Date.now(), timestamp: new Date().toISOString() };
    setLocal('care_ai_bookings', [newBooking, ...local]);
    return newBooking.id;
  }

  try {
    const docRef = await addDoc(collection(db, "bookings"), {
      ...bookingData,
      status: 'Chờ khám',
      timestamp: serverTimestamp()
    });
    return docRef.id;
  } catch (e) {
    console.error("Booking Error:", e);
    return null;
  }
};

export const fetchUserBookings = async (phone: string): Promise<Booking[]> => {
  if (!isFirebaseConfigured || !db) {
    const local = getLocal('care_ai_bookings') || [];
