    if (pendingDoctor && bookingDate) {
        setBookingTime(''); // Reset selected time
        checkAvailability(pendingDoctor.id, bookingDate).then(setOccupiedSlots);
    }
  }, [bookingDate, pendingDoctor]);

  const refreshAdminData = async () => {
    const [b, d, u] = await Promise.all([fetchAllBookings(), fetchDoctors(), fetchAllUsers()]);
    setAllBookings(b);
    setDoctors(d);
    setAllUsers(u);
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    setIsSubmitting(true);

    if (authMode === 'register') {
        const isAdmin = authData.phone === '000';
        const newUser: User = {
            username: authData.phone,
            phone: authData.phone,
            fullName: authData.fullName,
            password: authData.password,
            role: isAdmin ? 'admin' : 'customer'
        };
        const success = await registerUser(newUser);
        if (success) {
            setUser(newUser);
            localStorage.setItem('care_ai_user', JSON.stringify(newUser));
            setCurrentPage(isAdmin ? 'admin' : 'home');
        } else {
            setAuthError('Số điện thoại đã tồn tại!');
        }
    } else {
        const u = await loginUser(authData.phone, authData.password);
        if (u) {
            setUser(u);
            localStorage.setItem('care_ai_user', JSON.stringify(u));
            setCurrentPage(u.role === 'admin' ? 'admin' : 'home');
        } else {
            setAuthError('Sai số điện thoại hoặc mật khẩu!');
        }
    }
    setIsSubmitting(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('care_ai_user');
    setCurrentPage('home');
    setAuthData({ fullName: '', phone: '', password: '' });
  };

  const onCancelBooking = async (id: string) => {
    if (!confirm("Hủy lịch hẹn này?")) return;
    const ok = await updateBookingStatus(id, 'Đã hủy');
    if (ok) {
        if(user?.role === 'admin') refreshAdminData();
        setBookings(prev => prev.map(b => b.id === id ? {...b, status: 'Đã hủy'} : b));
    }
  };

  const onSaveDoctor = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingDoctor) return;
    await saveDoctor(editingDoctor as Doctor);
    await refreshAdminData();
    setShowDocModal(false);
    setEditingDoctor(null);
  };

  const filteredAdminBookings = useMemo(() => {
    return allBookings.filter(b => {
        const matchStatus = bookingFilterStatus === 'Tất cả' || b.status === bookingFilterStatus;
        const searchLower = bookingSearch.toLowerCase();
        const matchSearch = b.userFullName.toLowerCase().includes(searchLower) || 
                            b.doctorName.toLowerCase().includes(searchLower) ||
                            b.userPhone.includes(searchLower);
        return matchStatus && matchSearch;
    });
  }, [allBookings, bookingFilterStatus, bookingSearch]);

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin text-teal-600" size={40} /></div>;

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-20">
      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-100 px-6 py-4">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div onClick={() => setCurrentPage('home')} className="flex items-center gap-3 cursor-pointer">
            <div className="bg-slate-900 p-2 rounded-xl text-white"><Stethoscope size={24} /></div>
            <span className="font-black text-2xl tracking-tighter">CareAI</span>
          </div>

          <div className="hidden md:flex gap-1 bg-slate-100 p-1 rounded-xl">
            <NavBtn active={currentPage === 'home'} onClick={() => setCurrentPage('home')} icon={<HomeIcon size={18}/>} label="Trang chủ"/>
            <NavBtn active={currentPage === 'chat'} onClick={() => setCurrentPage('chat')} icon={<MessageSquare size={18}/>} label="Tư vấn AI"/>
            <NavBtn active={currentPage === 'doctors'} onClick={() => setCurrentPage('doctors')} icon={<Briefcase size={18}/>} label="Bác sĩ"/>
            <NavBtn active={currentPage === 'history'} onClick={() => setCurrentPage('history')} icon={<History size={18}/>} label="Lịch sử"/>
            {user?.role === 'admin' && <NavBtn active={currentPage === 'admin'} onClick={() => setCurrentPage('admin')} icon={<Settings size={18}/>} label="Admin"/>}
          </div>

          <div>
            {user ? (
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-teal-500 rounded-full flex items-center justify-center text-white font-bold">{user.fullName[0]}</div>
                <button onClick={handleLogout} className="text-slate-400 hover:text-red-500 transition-colors"><LogOut size={20}/></button>
              </div>
            ) : (
              <button onClick={() => setCurrentPage('auth')} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-bold hover:bg-teal-600 transition-all">Đăng nhập</button>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto p-6 mt-4">
        {currentPage === 'home' && (
          <div className="space-y-16 animate-fade-in">
             <section className="bg-slate-900 rounded-[3rem] p-12 text-white relative overflow-hidden">
                <div className="relative z-10 max-w-xl">
                  <h1 className="text-6xl font-black leading-tight mb-6">Y tế số <br/><span className="text-teal-400">thông minh</span></h1>
                  <p className="text-slate-400 text-lg mb-8">Hỏi đáp triệu chứng với AI và đặt lịch khám bác sĩ chuyên khoa chỉ trong 1 phút.</p>
                  <button onClick={() => setCurrentPage('chat')} className="bg-teal-500 text-slate-900 px-8 py-4 rounded-2xl font-black flex items-center gap-3 hover:scale-105 transition-all">
                    Bắt đầu tư vấn <ArrowRight size={20}/>
                  </button>
                </div>
                <div className="absolute right-0 top-0 w-1/2 h-full bg-gradient-to-l from-teal-500/10 to-transparent"></div>
             </section>
          </div>
        )}

        {currentPage === 'chat' && <div className="h-[75vh]"><ChatInterface onBook={(d) => { setSuggestedFilter(d.specialty); setCurrentPage('doctors'); }} /></div>}

        {currentPage === 'doctors' && <div className="h-[75vh]"><DoctorList doctors={doctors} initialFilter={suggestedFilter} onBook={(d) => { setPendingDoctor(d); if(!user) setCurrentPage('auth'); else { setBookingDate(''); setBookingTime(''); setShowBookingModal(true); } }} /></div>}

        {currentPage === 'history' && (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-3xl font-black">Lịch hẹn của bạn</h2>
            <div className="grid md:grid-cols-2 gap-6">
              {bookings.map(b => <BookingCard key={b.id} booking={b} onCancel={onCancelBooking} />)}
              {bookings.length === 0 && <p className="text-slate-400">Bạn chưa có lịch hẹn nào.</p>}
            </div>
          </div>
        )}

        {currentPage === 'admin' && user?.role === 'admin' && (
          <div className="space-y-8 animate-fade-in">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black">Admin Dashboard</h2>
              {adminTab === 'doctors' && (
                  <button onClick={() => { setEditingDoctor({ name: '', specialty: Specialty.GENERAL, price: 200000, experience: 5, image: 'https://picsum.photos/200' }); setShowDocModal(true); }} className="bg-teal-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2"><Plus size={20}/> Thêm bác sĩ</button>
              )}
            </div>

            {/* Admin Tabs */}
            <div className="flex gap-4 border-b border-slate-200 pb-1">
                <button onClick={() => setAdminTab('bookings')} className={`px-4 py-2 font-bold text-sm ${adminTab === 'bookings' ? 'text-teal-600 border-b-2 border-teal-600' : 'text-slate-400'}`}>Lịch hẹn</button>
                <button onClick={() => setAdminTab('doctors')} className={`px-4 py-2 font-bold text-sm ${adminTab === 'doctors' ? 'text-teal-600 border-b-2 border-teal-600' : 'text-slate-400'}`}>Bác sĩ</button>
                <button onClick={() => setAdminTab('users')} className={`px-4 py-2 font-bold text-sm ${adminTab === 'users' ? 'text-teal-600 border-b-2 border-teal-600' : 'text-slate-400'}`}>Người dùng</button>
            </div>

            {adminTab === 'bookings' && (
                <div className="space-y-4">
                    <div className="flex gap-4 items-center bg-white p-4 rounded-2xl border border-slate-100">
                        <Filter size={18} className="text-slate-400"/>
                        <select className="bg-transparent font-bold text-slate-700 outline-none" value={bookingFilterStatus} onChange={e => setBookingFilterStatus(e.target.value)}>
                            <option value="Tất cả">Tất cả trạng thái</option>
                            <option value="Chờ khám">Chờ khám</option>
                            <option value="Đã hoàn thành">Đã hoàn thành</option>
                            <option value="Đã hủy">Đã hủy</option>
                        </select>
                        <div className="h-6 w-px bg-slate-200 mx-2"></div>
                        <Search size={18} className="text-slate-400"/>
                        <input placeholder="Tìm theo tên khách, bác sĩ..." className="flex-1 bg-transparent outline-none" value={bookingSearch} onChange={e => setBookingSearch(e.target.value)} />
                    </div>
                    <div className="grid gap-4">
                        {filteredAdminBookings.map(b => (
                             <div key={b.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className={`w-2 h-2 rounded-full ${b.status === 'Chờ khám' ? 'bg-amber-400' : b.status === 'Đã hủy' ? 'bg-slate-300' : 'bg-green-500'}`}></span>
                                        <span className="font-bold">{b.userFullName}</span>
                                        <span className="text-xs text-slate-400">({b.userPhone})</span>
                                    </div>
                                    <p className="text-sm text-slate-600">Khám <span className="font-bold">{b.doctorName}</span> lúc <span className="font-bold text-teal-600">{b.time} - {b.date}</span></p>
                                </div>
                                {b.status === 'Chờ khám' && (
                                    <div className="flex gap-2">
                                        <button onClick={() => updateBookingStatus(b.id, 'Đã hoàn thành').then(refreshAdminData)} className="p-2 bg-green-50 text-green-600 rounded-lg font-bold text-xs hover:bg-green-100">Hoàn thành</button>
                                        <button onClick={() => updateBookingStatus(b.id, 'Đã hủy').then(refreshAdminData)} className="p-2 bg-red-50 text-red-600 rounded-lg font-bold text-xs hover:bg-red-100">Hủy</button>
                                    </div>
                                )}
                                {b.status !== 'Chờ khám' && <span className="text-xs font-bold text-slate-400">{b.status}</span>}
                             </div>
                        ))}
                    </div>
                </div>
            )}

            {adminTab === 'doctors' && (
                 <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-100">
                      <tr>
                        <th className="p-4 font-bold text-xs uppercase text-slate-400">Bác sĩ</th>
                        <th className="p-4 font-bold text-xs uppercase text-slate-400">Chuyên khoa</th>
                        <th className="p-4 font-bold text-xs uppercase text-slate-400">Giá</th>
                        <th className="p-4 font-bold text-xs uppercase text-slate-400">Hành động</th>
                      </tr>
                    </thead>
                    <tbody>
                      {doctors.map(d => (
                        <tr key={d.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                          <td className="p-4 flex items-center gap-3">
                            <img src={d.image} className="w-10 h-10 rounded-full object-cover" />
                            <span className="font-bold">{d.name}</span>
                          </td>
                          <td className="p-4 text-sm text-slate-500">{d.specialty}</td>
                          <td className="p-4 text-sm font-bold">{d.price.toLocaleString()}đ</td>
                          <td className="p-4">
                            <div className="flex gap-2">
                              <button onClick={() => { setEditingDoctor(d); setShowDocModal(true); }} className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg"><Edit size={16}/></button>
                              <button onClick={async () => { if(confirm("Xóa bác sĩ?")) { await deleteDoctor(d.id); refreshAdminData(); }}} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16}/></button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
            )}

            {adminTab === 'users' && (
                <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden">
                    <table className="w-full text-left">
                        <thead className="bg-slate-50 border-b border-slate-100">
                            <tr>
                                <th className="p-4 font-bold text-xs uppercase text-slate-400">Tên</th>
                                <th className="p-4 font-bold text-xs uppercase text-slate-400">Số điện thoại</th>
                                <th className="p-4 font-bold text-xs uppercase text-slate-400">Role</th>
                            </tr>
                        </thead>
                        <tbody>
                            {allUsers.map(u => (
                                <tr key={u.phone} className="border-b border-slate-50">
                                    <td className="p-4 font-bold text-slate-700">{u.fullName}</td>
                                    <td className="p-4 text-slate-500">{u.phone}</td>
                                    <td className="p-4"><span className={`px-2 py-1 rounded text-xs font-bold ${u.role === 'admin' ? 'bg-purple-100 text-purple-600' : 'bg-slate-100 text-slate-500'}`}>{u.role}</span></td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
          </div>
        )}

        {currentPage === 'auth' && (
          <div className="flex justify-center py-10 animate-slide-up">
            <form onSubmit={handleAuth} className="bg-white p-10 rounded-[2.5rem] shadow-2xl w-full max-w-md border border-slate-100">
               <div className="flex justify-center mb-6">
                   <div className="flex bg-slate-100 p-1 rounded-xl">
                       <button type="button" onClick={() => {setAuthMode('login'); setAuthError('');}} className={`px-6 py-2 rounded-lg font-bold text-sm transition-all ${authMode === 'login' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}>Đăng nhập</button>
                       <button type="button" onClick={() => {setAuthMode('register'); setAuthError('');}} className={`px-6 py-2 rounded-lg font-bold text-sm transition-all ${authMode === 'register' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}>Đăng ký</button>
                   </div>
               </div>

               <h2 className="text-3xl font-black mb-2 text-center">{authMode === 'login' ? 'Chào mừng trở lại' : 'Tạo tài khoản mới'}</h2>
               {authMode === 'register' && <p className="text-center text-slate-400 mb-6 text-sm">Nhập thông tin cá nhân của bạn</p>}
               {authMode === 'login' && <p className="text-center text-slate-400 mb-6 text-sm">Đăng nhập để quản lý lịch khám</p>}

               {authError && <div className="bg-red-50 text-red-500 p-3 rounded-xl text-center text-sm font-bold mb-4">{authError}</div>}

               <div className="space-y-4">
                  {authMode === 'register' && (
                      <div className="relative">
                        <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18}/>
                        <input required type="text" placeholder="Họ và tên" className="w-full bg-slate-50 border-0 rounded-2xl pl-12 pr-4 py-4 ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500 outline-none" onChange={e => setAuthData({...authData, fullName: e.target.value})} />
                      </div>
                  )}
                  <div className="relative">
                    <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18}/>
                    <input required type="tel" placeholder="Số điện thoại" className="w-full bg-slate-50 border-0 rounded-2xl pl-12 pr-4 py-4 ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500 outline-none" onChange={e => setAuthData({...authData, phone: e.target.value})} />
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18}/>
                    <input required type="password" placeholder="Mật khẩu" className="w-full bg-slate-50 border-0 rounded-2xl pl-12 pr-4 py-4 ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500 outline-none" onChange={e => setAuthData({...authData, password: e.target.value})} />
                  </div>

                  <button disabled={isSubmitting} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-slate-800 transition-all flex justify-center">
                      {isSubmitting ? <Loader2 className="animate-spin"/> : (authMode === 'login' ? 'Đăng nhập' : 'Đăng ký ngay')}
                  </button>
               </div>
            </form>
          </div>
        )}
      </main>

      {/* MODAL: ADMIN EDIT DOCTOR */}
      {showDocModal && editingDoctor && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 animate-slide-up shadow-2xl max-h-[90vh] overflow-y-auto">
              <h3 className="text-2xl font-black mb-6">Thông tin bác sĩ</h3>
              <form onSubmit={onSaveDoctor} className="space-y-4">
                 <input required value={editingDoctor.name} placeholder="Tên bác sĩ" className="w-full border-slate-200 rounded-xl p-3 border outline-none focus:border-teal-500" onChange={e => setEditingDoctor({...editingDoctor, name: e.target.value})} />
                 <select value={editingDoctor.specialty} className="w-full border-slate-200 rounded-xl p-3 border outline-none" onChange={e => setEditingDoctor({...editingDoctor, specialty: e.target.value as Specialty})}>
                   {Object.values(Specialty).map(s => <option key={s} value={s}>{s}</option>)}
                 </select>
                 <div className="grid grid-cols-2 gap-4">
                    <input type="number" value={editingDoctor.price} placeholder="Giá khám" className="w-full border-slate-200 rounded-xl p-3 border outline-none" onChange={e => setEditingDoctor({...editingDoctor, price: Number(e.target.value)})} />
                    <input type="number" value={editingDoctor.experience} placeholder="Số năm KN" className="w-full border-slate-200 rounded-xl p-3 border outline-none" onChange={e => setEditingDoctor({...editingDoctor, experience: Number(e.target.value)})} />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 ml-1 block mb-1">Link Ảnh Bác Sĩ (URL)</label>
                    <input type="url" value={editingDoctor.image} placeholder="https://..." className="w-full border-slate-200 rounded-xl p-3 border outline-none" onChange={e => setEditingDoctor({...editingDoctor, image: e.target.value})} />
                 </div>
                 <div className="flex gap-4 pt-4">
                    <button type="button" onClick={() => setShowDocModal(false)} className="flex-1 py-4 font-bold text-slate-500 hover:bg-slate-50 rounded-2xl">Hủy</button>
                    <button type="submit" className="flex-1 bg-teal-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-teal-100">Lưu lại</button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* MODAL: BOOKING (NEW LOGIC) */}
      {showBookingModal && pendingDoctor && (
        <div className="fixed inset-0 z-[100] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4">
           <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 animate-slide-up shadow-2xl relative overflow-hidden">
             {bookingSuccess ? (
               <div className="py-10 space-y-4 text-center">
                 <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto"><CheckCircle size={40}/></div>
                 <h4 className="text-2xl font-black">Đặt lịch thành công!</h4>
                 <p className="text-slate-500">Mã lịch hẹn đã được lưu. Vui lòng đến đúng giờ.</p>
               </div>
             ) : (
               <div className="space-y-6">
                 <div className="flex justify-between items-start">
                     <div>
                        <h3 className="text-2xl font-black">Đặt lịch khám</h3>
                        <p className="text-sm text-slate-500">{pendingDoctor.name}</p>
                     </div>
                     <button onClick={() => setShowBookingModal(false)} className="bg-slate-100 p-2 rounded-full hover:bg-slate-200"><X size={20}/></button>
                 </div>

                 {/* Step 1: Select Date */}
                 <div className="space-y-2">
                    <label className="font-bold text-sm text-slate-700 flex items-center gap-2"><Calendar size={16}/> Chọn ngày khám</label>
                    <input 
                        type="date" 
                        min={today}
                        max={maxDateStr}
                        value={bookingDate}
                        onChange={(e) => setBookingDate(e.target.value)}
                        className="w-full bg-slate-50 border-0 rounded-xl p-4 font-bold text-slate-700 outline-none ring-1 ring-slate-200 focus:ring-2 focus:ring-teal-500"
                    />
                 </div>

                 {/* Step 2: Select Time Slot */}
                 <div className="space-y-2">
                    <label className="font-bold text-sm text-slate-700 flex items-center gap-2"><Clock size={16}/> Chọn giờ khám</label>
                    {bookingDate ? (
                         <div className="grid grid-cols-3 gap-2">
                            {TIME_SLOTS.map(slot => {
                                const isOccupied = occupiedSlots.includes(slot);
                                const isSelected = bookingTime === slot;
                                return (
                                    <button
                                        key={slot}
                                        disabled={isOccupied}
                                        onClick={() => setBookingTime(slot)}
                                        className={`py-3 rounded-xl font-bold text-sm transition-all border
                                            ${isOccupied ? 'bg-slate-100 text-slate-300 border-transparent cursor-not-allowed' : 
                                              isSelected ? 'bg-teal-600 text-white border-teal-600 shadow-md shadow-teal-200' : 
                                              'bg-white text-slate-600 border-slate-200 hover:border-teal-500 hover:text-teal-600'
                                            }`}
                                    >
                                        {slot} {isOccupied && '(Đã kín)'}
                                    </button>
                                )
                            })}
                         </div>
                    ) : (
                        <div className="p-4 bg-slate-50 rounded-xl text-center text-slate-400 text-sm italic">Vui lòng chọn ngày trước</div>
                    )}
                 </div>

                 <div className="pt-4 border-t border-slate-100">
                     <div className="flex justify-between mb-4 text-sm">
                         <span className="text-slate-500">Phí khám:</span>
                         <span className="font-bold text-slate-900">{pendingDoctor.price.toLocaleString()}đ</span>
                     </div>
                     <button 
                        disabled={isSubmitting || !bookingDate || !bookingTime} 
                        onClick={async () => {
                            setIsSubmitting(true);
                            // Double check availability
                            const freshOccupied = await checkAvailability(pendingDoctor.id, bookingDate);
                            if (freshOccupied.includes(bookingTime)) {
                                alert("Rất tiếc, khung giờ này vừa có người đặt. Vui lòng chọn giờ khác.");
                                setOccupiedSlots(freshOccupied);
                                setIsSubmitting(false);
                                return;
                            }

                            const ok = await saveBooking({ 
                                doctorId: pendingDoctor.id, 
                                doctorName: pendingDoctor.name, 
                                doctorImage: pendingDoctor.image, 
                                specialty: pendingDoctor.specialty, 
                                date: bookingDate, 
                                time: bookingTime,
                                userPhone: user?.phone, 
                                userFullName: user?.fullName 
                            });

                            if(ok) { 
                                setBookingSuccess(true); 
                                setTimeout(() => { 
                                    setShowBookingModal(false); 
                                    setBookingSuccess(false); 
                                    setBookingDate('');
                                    setBookingTime('');
                                    setCurrentPage('history'); 
                                }, 2000); 
                            }
                            setIsSubmitting(false);
                        }} 
                        className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold shadow-xl disabled:bg-slate-300 disabled:cursor-not-allowed hover:scale-[1.02] transition-transform"
                     >
                        {isSubmitting ? <Loader2 className="animate-spin mx-auto"/> : "Xác nhận đặt lịch"}
                     </button>
                 </div>
               </div>
             )}
           </div>
        </div>
      )}
    </div>
  );
}

