                     </div>
                     <button 
                        disabled={isSubmitting || !bookingDate || !bookingTime} 
                        onClick={async () => {
                            setIsSubmitting(true);
                            const freshOccupied = await checkAvailability(pendingDoctor.id, bookingDate);
                            if (freshOccupied.includes(bookingTime)) {
                                alert("Rất tiếc, khung giờ này vừa có người đặt. Vui lòng chọn giờ khác.");
                                setOccupiedSlots(freshOccupied);
                                setIsSubmitting(false);
                                return;
                            }

                            const ok = await saveBooking({ 
                                doctorId: pendingDoctor.id, 
                                doctorName: pendingDoctor.name, 
                                doctorImage: pendingDoctor.image, 
                                specialty: pendingDoctor.specialty, 
                                date: bookingDate, 
                                time: bookingTime,
                                userPhone: user?.phone, 
                                userFullName: user?.fullName 
                            });

                            if(ok) { 
                                setBookingSuccess(true); 
                                setTimeout(() => { 
                                    setShowBookingModal(false); 
                                    setBookingSuccess(false); 
                                    setBookingDate('');
                                    setBookingTime('');
                                    setCurrentPage('history'); 
                                }, 2000); 
                            }
