                                if (!file) return;

                                // Kiểm tra kích thước (Max 5MB cho file gốc, sau đó ta sẽ nén)
                                if (file.size > 5 * 1024 * 1024) {
                                  alert("File ảnh quá lớn (tối đa 5MB). Hệ thống sẽ tự nén nếu nhỏ hơn.");
                                  e.target.value = '';
                                  return;
                                }

                                if(editingDoctor) {
                                    setIsUploading(true);
                                    try {
                                      const url = await uploadDoctorImage(file);
                                      setEditingDoctor(prev => prev ? {...prev, image: url} : prev);
