        const userBks = await fetchUserBookings(u.phone);
        setBookings(userBks);
      }
      setLoading(false);
    };
    init();
  }, []);

  useEffect(() => {
    if (user?.role === 'admin' && currentPage === 'admin') refreshAdminData();
