                                    >
                                      {isDeletingId === d.id ? <Loader2 size={16} className="animate-spin"/> : <Trash2 size={16}/>}
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                    {doctors.length === 0 && <p className="text-slate-400 col-span-full py-10 text-center">Chưa có bác sĩ nào trong hệ thống.</p>}
