                    <button disabled={!bookingDate || !bookingTime} onClick={async () => { setIsSubmitting(true); const ok = await saveBooking({ doctorId: pendingDoctor.id, doctorName: pendingDoctor.name, doctorImage: pendingDoctor.image, specialty: pendingDoctor.specialty, date: bookingDate, time: bookingTime, userPhone: user?.phone, userFullName: user?.fullName, aiSummary: bookingSummary }); if (ok) { setBookingSuccess(true); refreshAdminData(); setTimeout(() => { setShowBookingModal(false); setBookingSuccess(false); setCurrentPage('history'); }, 2000); } setIsSubmitting(false); }} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black shadow-2xl">Xác nhận lịch khám</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
}

