    const snap = await getDocs(q);
    const results = snap.docs.map(doc => ({ 
      id: doc.id, 
      ...doc.data(), 
      timestamp: doc.data().timestamp?.toDate() || new Date() 
    } as Booking));
    return results.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
  } catch (e) {
    return [];
  }
};

