                        <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="w-full text-slate-400 text-sm">{authMode === 'login' ? 'Bạn mới? Tạo tài khoản' : 'Đã có tài khoản? Đăng nhập'}</button>
                    </div>
                </form>
            </div>
        )}
