          <div className="flex-1">
            <h4 className={`font-bold text-sm ${toast.type === 'success' ? 'text-teal-700' : toast.type === 'error' ? 'text-red-700' : 'text-blue-700'}`}>
              {toast.type === 'success' ? 'Thành công' : toast.type === 'error' ? 'Lỗi' : 'Thông báo'}
